156	fn pack_round_trips_yaml() {
157	    let dir = tempfile::tempdir().unwrap();
158	    let pack = hd2_pack();
159	
160	    pack.save_to_dir(dir.path()).expect("save must succeed");
161	
162	    let yaml_path = dir.path().join("pack.yaml");
163	    assert!(yaml_path.exists(), "pack.yaml must be written");
164	
165	    let loaded = Pack::load_from_dir(dir.path()).expect("load must succeed");
166	    assert_eq!(loaded.name, "Helldivers 2");
167	    assert_eq!(loaded.author, Some("community".to_string()));
168	    assert_eq!(loaded.categories.len(), 3);
169	}
