185	fn pack_flatten_preserves_macro_fields() {
186	    let pack = hd2_pack();
187	    let flat = pack.flatten();
188	
189	    let reinforce = flat.iter().find(|m| m.name == "Reinforce").unwrap();
190	    assert_eq!(reinforce.phrase, Some("reinforce".to_string()));
191	    assert_eq!(reinforce.keys.len(), 5);
192	    assert_eq!(reinforce.keys[0].key, "KEY_W");
