328	#[serial]
329	fn pack_import_from_zip_reads_name_and_macros() {
330	    // Build a zip in a temp dir, import it, and verify the imported pack content.
331	    // import() extracts to XDG_CONFIG_HOME/vibe-attack/profiles/<name>.
332	    // We redirect XDG_CONFIG_HOME to a second temp dir to stay hermetic.
333	    let source_dir = tempfile::tempdir().unwrap();
334	    let import_root = tempfile::tempdir().unwrap();
335	
336	    let pack = Pack {
337	        name: "ImportTest".to_string(),
338	        author: Some("tester".to_string()),
339	        categories: vec![Category {
340	            name: "Test".to_string(),
341	            macros: vec![macro_simple(
342	                "Reinforce",
343	                "reinforce",
344	                vec![key("KEY_W"), key("KEY_S")],
345	            )],
346	        }],
347	    };
348	    pack.save_to_dir(source_dir.path()).unwrap();
349	
350	    let zip_path = source_dir.path().join("importtest.hdpack");
351	    pack.export(source_dir.path(), &zip_path).unwrap();
352	
353	    // Redirect XDG so import() writes into our temp dir, not the real config home.
354	    std::env::set_var("XDG_CONFIG_HOME", import_root.path());
355	    let imported = Pack::import(&zip_path).expect("import must succeed");
356	    std::env::remove_var("XDG_CONFIG_HOME");
357	
358	    assert_eq!(imported.name, "ImportTest");
359	    assert_eq!(imported.author, Some("tester".to_string()));
360	    assert_eq!(imported.categories.len(), 1);
361	
362	    let flat = imported.flatten();
363	    assert_eq!(flat.len(), 1);
364	    assert_eq!(flat[0].name, "Reinforce");
365	}
