520	#[test]
521	#[serial]
522	fn hd2_pack_full_lifecycle_export_import_activate_retrieve() {
523	    let export_dir = tempfile::tempdir().unwrap();
524	    let config_root = tempfile::tempdir().unwrap();
525	
526	    // 1. Build and export the HD2 pack
527	    let pack = hd2_pack();
528	    pack.save_to_dir(export_dir.path()).unwrap();
529	    let zip_path = export_dir.path().join("helldivers2.hdpack");
530	    pack.export(export_dir.path(), &zip_path).unwrap();
531	
532	    // 2. Import it (extracts to profiles/Helldivers 2/)
533	    std::env::set_var("XDG_CONFIG_HOME", config_root.path());
534	    let imported = Pack::import(&zip_path).expect("import must succeed");
535	    assert_eq!(imported.name, "Helldivers 2");
536	
537	    // 3. Set as active profile and retrieve it
538	    let manager = ProfileManager {
539	        active_profile: Some("Helldivers 2".to_string()),
540	    };
541	    let active = manager
542	        .get_active_pack()
543	        .expect("get_active_pack must succeed")
544	        .expect("active pack must be present");
545	    std::env::remove_var("XDG_CONFIG_HOME");
546	
547	    assert_eq!(active.name, "Helldivers 2");
548	    let flat = active.flatten();
549	    assert_eq!(flat.len(), 9);
550	
551	    // Verify key stratagem is intact after the full lifecycle
552	    let reinforce = flat.iter().find(|m| m.name == "Reinforce").unwrap();
553	    assert_eq!(reinforce.phrase, Some("reinforce".to_string()));
554	    assert_eq!(reinforce.keys.len(), 5);
555	}
